pub fn normalize_spaces(input: &str) -> String {
    let mut out = String::new();
    let mut prev_space = false;
    let mut saw_non_whitespace = false;

    for ch in input.chars() {
        if ch.is_whitespace() {
            if !prev_space && saw_non_whitespace {
                out.push(' ');
                prev_space = true;
            }
        } else {
            out.push(ch);
            prev_space = false;
            saw_non_whitespace = true;
        }
    }

    if prev_space {
        out.push(' ');
    }

    out
}

