pub fn tokenize(input: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut current = String::new();
    let mut prev_lower = false;

    for ch in input.chars() {
        if ch == '_' || ch == '-' || ch.is_whitespace() {
            if !current.is_empty() {
                out.push(std::mem::take(&mut current));
            }
            prev_lower = false;
            continue;
        }

        if ch.is_ascii_uppercase() && prev_lower {
            out.push(std::mem::take(&mut current));
        }

        if ch.is_ascii_digit() {
            if !current.is_empty() {
                out.push(std::mem::take(&mut current));
            }
            current.push(ch);
            out.push(std::mem::take(&mut current));
            prev_lower = false;
            continue;
        }

        current.push(ch.to_ascii_lowercase());
        prev_lower = ch.is_ascii_lowercase();
    }

    if !current.is_empty() {
        out.push(current);
    }

    out
}

#[cfg(test)]
mod tests {
    use super::tokenize;

    #[test]
    fn splits_common_separators() {
        assert_eq!(tokenize("alpha_beta-gamma delta"), vec!["alpha", "beta", "gamma", "delta"]);
    }

    #[test]
    fn splits_camel_case() {
        assert_eq!(tokenize("parseHTTPHeader"), vec!["parse", "httpheader"]);
        assert_eq!(tokenize("userIDValue"), vec!["user", "idvalue"]);
    }

    #[test]
    fn keeps_digits_with_preceding_token() {
        assert_eq!(tokenize("release2024_build7"), vec!["release2024", "build7"]);
        assert_eq!(tokenize("Version2Update"), vec!["version2", "update"]);
    }

    #[test]
    fn ignores_repeated_separators() {
        assert_eq!(tokenize("__mix--Of  Things__"), vec!["mix", "of", "things"]);
    }
}

