pub fn normalize_words(input: &str) -> String {
    let mut out = Vec::new();
    for part in input.split_whitespace() {
        let cleaned = part
            .chars()
            .filter(|c| c.is_ascii_alphanumeric() || *c == '-' || *c == '_')
            .collect::<String>()
            .to_ascii_lowercase();
        if !cleaned.is_empty() {
            out.push(cleaned);
        }
    }
    out.join(" ")
}

#[cfg(test)]
mod tests {
    use super::normalize_words;

    #[test]
    fn trims_outer_whitespace_and_lowercases() {
        assert_eq!(normalize_words("  Hello WORLD  "), "hello world");
    }

    #[test]
    fn keeps_internal_spacing_between_nonempty_segments() {
        assert_eq!(normalize_words("One\t\tTwo   Three"), "one two three");
    }

    #[test]
    fn strips_surrounding_punctuation_but_keeps_inner_dashes_and_underscores() {
        assert_eq!(normalize_words("..Alpha-BETA!! __MiXed__ ???"), "alpha-beta __mixed__");
    }

    #[test]
    fn drops_tokens_that_become_empty_after_cleaning() {
        assert_eq!(normalize_words("*** keep ??? __ok__ !!!"), "keep __ok__");
    }

    #[test]
    fn preserves_unicode_letters_only_when_they_are_ascii_alnum() {
        assert_eq!(normalize_words("Caf NUM8"), "caf num8");
    }

    #[test]
    fn keeps_digit_only_tokens() {
        assert_eq!(normalize_words("  007 ... 42!! "), "007 42");
    }
}

