pub fn normalize_words(input: &str) -> String {
    input
        .split_whitespace()
        .filter_map(|part| {
            let start = part
                .find(|c: char| c.is_ascii_alphanumeric() || c == '_' || c == '-')?;
            let end = part
                .rfind(|c: char| c.is_ascii_alphanumeric() || c == '_' || c == '-')?;
            let cleaned = part[start..=end].to_ascii_lowercase();
            if cleaned.is_empty() {
                None
            } else {
                Some(cleaned)
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

