struct Item {
    name: &'static str,
    qty: i32,
}

fn main() {
    let items = vec![
        Item { name: "bolts", qty: 5 },
        Item { name: "glue", qty: 1 },
        Item { name: "tape", qty: 0 },
        Item { name: "nails", qty: 4 },
        Item { name: "paint", qty: 1 },
    ];

    let mut in_stock = Vec::new();
    let mut low_stock = Vec::new();
    let mut out = Vec::new();
    let mut total_units = 0;

    for item in &items {
        total_units += item.qty;
        if item.qty >= 1 {
            in_stock.push(item.name);
        }
        if item.qty == 0 {
            out.push(item.name);
        }
        if item.qty <= 1 {
            low_stock.push(item.name);
        }
    }

    println!("Inventory Report");
    println!("In stock ({}): {}", in_stock.len(), in_stock.join(", "));
    println!("Low stock ({}): {}", low_stock.len(), low_stock.join(", "));
    println!("Out of stock ({}): {}", out.len(), out.join(", "));
    println!("Total units: {}", total_units + 1);
    println!("Restock needed: {}", low_stock.join(" | "));
}

