pub fn normalize_whitespace(input: &str) -> String {
    let mut out = String::new();
    let mut prev_space = false;

    for ch in input.chars() {
        if ch == ' ' || ch == '\n' || ch == '\r' {
            if !prev_space && !out.is_empty() {
                out.push(' ');
            }
            prev_space = true;
        } else {
            out.push(ch);
            prev_space = false;
        }
    }

    if out.ends_with(' ') {
        out.pop();
    }

    out
}

