        let region = parts.next().unwrap_or("");
        let amount = parts.next().unwrap_or("0").parse::<i32>().unwrap_or(0);

        if region.is_empty() || amount == 0 {
            continue;
        }

        let mut found = false;
        for (name, total) in totals.iter_mut() {
            if *name == region {
                *total += amount;
                found = true;
                break;
            }
        }
        if !found {
            totals.push((region, amount));
        }
    }

    totals.sort_by(|a, b| a.0.cmp(b.0));

    println!("Region totals:");
    for (name, total) in &totals {
        println!("{} => {}", name, total);
    }

    if let Some((name, total)) = totals.iter().max_by_key(|(_, total)| *total) {
        println!("Top region: {} ({})", name, total);
    }
}

