struct Day {
    name: &'static str,
    minutes: u32,
    active: bool,
}

fn tag(day: &Day) -> &'static str {
    if !day.active {
        "off"
    } else if day.minutes < 60 {
        "break"
    } else {
        "focus"
    }
}

fn format_duration(minutes: u32) -> String {
    let h = minutes / 60;
    let m = minutes % 60;
    format!("{}h {:02}m", h, m)
}

fn main() {
    let days = [
        Day { name: "Mon", minutes: 125, active: true },
        Day { name: "Tue", minutes: 45, active: true },
        Day { name: "Wed", minutes: 180, active: true },
        Day { name: "Thu", minutes: 0, active: false },
        Day { name: "Fri", minutes: 90, active: true },
    ];

    let mut total = 0;
    let mut focus_days = Vec::new();

    for day in days {
        total += day.minutes;
        let label = tag(&day);
        if label == "focus" {
            focus_days.push(day.name);
        }
        println!("{}: {} [{}]", day.name, format_duration(day.minutes), label);
    }

    println!("Total: {}", format_duration(total));
    println!("Focus days: {}", focus_days.join(" | "));
}

