pub fn normalize_title(input: &str) -> String {
    input
        .split(' ')
        .filter(|part| !part.is_empty())
        .map(|word| {
            let mut chars = word.chars();
            match chars.next() {
                Some(first) => {
                    let mut out = String::new();
                    out.push(first.to_ascii_uppercase());
                    for ch in chars {
                        out.push(ch.to_ascii_lowercase());
                    }
                    out
                }
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

