pub fn normalize_slug(input: &str) -> String {
    let mut out = String::new();
    let mut prev_dash = false;

    for ch in input.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
            prev_dash = false;
        } else if ch == ' ' || ch == '_' || ch == '-' {
            if !prev_dash {
                out.push('-');
                prev_dash = true;
            }
        }
    }

    out
}

#[cfg(test)]
mod tests {
    use super::normalize_slug;

    #[test]
    fn trims_edges_and_collapses_separators() {
        assert_eq!(normalize_slug("  Hello__World  "), "hello-world");
    }

    #[test]
    fn strips_punctuation_without_inserting_dash() {
        assert_eq!(normalize_slug("Rust!Lang???"), "rustlang");
    }

    #[test]
    fn non_ascii_letters_act_as_separators() {
        assert_eq!(normalize_slug("Crème brûlée"), "cr-me-br-l-e");
    }

    #[test]
    fn drops_separator_only_content() {
        assert_eq!(normalize_slug("__ --   __"), "");
    }

    #[test]
    fn preserves_digits() {
        assert_eq!(normalize_slug("Version 2_0-beta"), "version-2-0-beta");
    }
}

