pub fn normalize_title(input: &str) -> String {
    let mut out = String::new();
    let mut new_word = true;

    for ch in input.chars() {
        if ch == ' ' || ch == '-' || ch == '\'' {
            out.push(ch);
            new_word = true;
        } else if new_word {
            for c in ch.to_uppercase() {
                out.push(c);
            }
            new_word = false;
        } else {
            for c in ch.to_lowercase() {
                out.push(c);
            }
        }
    }

    out
}

