pub fn repeat_word(word: &str, times: usize) -> String {
    if times == 0 {
        return String::new();
    }

    let mut out = String::new();
    for i in 0..times {
        if i > 0 {
            out.push(' ');
        }
        out.push_str(word);
    }
    out
}

pub fn filter_labels(labels: &[&str], query: &str) -> String {
    let q = query.trim().to_ascii_lowercase();
    let mut picked: Vec<String> = labels
        .iter()
        .filter_map(|label| {
            let trimmed = label.trim();
            if trimmed.is_empty() {
                return None;
            }

            let lower = trimmed.to_ascii_lowercase();
            if q.is_empty() || lower.contains(&q) {
                Some(trimmed.to_string())
            } else {
                None
            }
        })
        .collect();

    picked.sort_by_key(|s| (s.len(), s.to_ascii_lowercase()));

    if picked.is_empty() {
        "no matches".to_string()
    } else {
        picked.join(" | ")
    }
}

#[cfg(test)]
mod tests {
    use super::filter_labels;

    #[test]
    fn finds_case_insensitive_matches() {
        let labels = [" Alpha ", "beta", "Gamma", "alphabet"];
        assert_eq!(filter_labels(&labels, "AlP"), "Alpha | alphabet");
    }

    #[test]
    fn ignores_blank_entries_and_reports_none() {
        let labels = [" ", "   ", "Beta"];
        assert_eq!(filter_labels(&labels, "zz"), "no matches");
    }
}

